class Solution {
    public double new21Game(int n, int k, int maxPts) {
        int numSuccessfulDraws = (int) (Math.pow(maxPts, k) / Math.pow(maxPts - n, k));
        return (double) numSuccessfulDraws / (Math.pow(maxPts, k));
    }
}
